// ============================================================
// MOVE ACTOR
// ============================================================
function moveActor(actor: Actor): boolean {
  if (actor.moveDir === DI_NODIR) return false;
  return tryMove(actor, actor.x + xspeed[actor.moveDir], actor.y + yspeed[actor.moveDir]);
}

// ============================================================
// RECURSIVE SOUND
// ============================================================
function recursiveSound(sec: Sector, blocks: number): void {
  if (sec.validCount === validCount) return; // already flooded
  sec.validCount = validCount;
  sec.soundTarget = soundTarget;
}
